const items = [];

for (const item of $input.all()) {
  const systemPrompt = `You are an expert procurement and vendor evaluation specialist with 15+ years of experience. Your role is to objectively score vendor RFP responses across multiple dimensions.

EVALUATION CRITERIA:
1. PRICE (0-10): Cost-effectiveness, value for money, transparent pricing
2. CAPABILITIES (0-10): Technical features, scalability, innovation
3. COMPLIANCE (0-10): Certifications (SOC2, ISO27001, GDPR, HIPAA)
4. SLA (0-10): Uptime guarantees, support responsiveness, penalties
5. REFERENCES (0-10): Quality and relevance of client references

SCORING GUIDELINES:
- 0-3: Poor/Unacceptable
- 4-6: Adequate/Meets minimum requirements
- 7-8: Good/Competitive
- 9-10: Excellent/Industry-leading

WEIGHTED FORMULA:
Total Score = (Price × 0.25) + (Capabilities × 0.30) + (Compliance × 0.20) + (SLA × 0.15) + (References × 0.10)

CRITICAL: You MUST respond with ONLY valid JSON. No markdown, no explanations outside JSON.`;

  const userPrompt = `Evaluate this vendor RFP response:

VENDOR: ${item.json.vendor_name}
EMAIL: ${item.json.vendor_email}

RESPONSE TEXT:
${item.json.raw_response}

EXTRACTED FIELDS (if available):
- Pricing: ${item.json.extracted_fields.pricing || 'Not found'}
- Features: ${item.json.extracted_fields.features || 'Not found'}
- SLA: ${item.json.extracted_fields.sla || 'Not found'}
- Compliance: ${item.json.extracted_fields.compliance || 'Not found'}
- References: ${item.json.extracted_fields.references || 'Not found'}

INSTRUCTIONS:
1. Score each dimension (0-10) based on the criteria
2. Calculate weighted total score
3. Identify ALL missing critical fields
4. Flag any risks (e.g., no compliance certs, vague SLA, no references)
5. Provide 2-sentence summary

OUTPUT FORMAT (STRICT JSON):
{
  "vendor_name": "string",
  "scores": {
    "price": number,
    "capabilities": number,
    "compliance": number,
    "sla": number,
    "references": number
  },
  "total_score": number,
  "missing_fields": ["array of missing fields"],
  "risk_flags": ["array of risk items"],
  "summary": "string",
  "raw_scores_justification": {
    "price": "brief reason",
    "capabilities": "brief reason",
    "compliance": "brief reason",
    "sla": "brief reason",
    "references": "brief reason"
  }
}`;

  items.push({
    json: {
      messages: [
        {
          role: "system",
          content: systemPrompt
        },
        {
          role: "user",
          content: userPrompt
        }
      ],
      vendor_data: item.json // Pass through for later use
    }
  });
}

return items;

const items = [];

for (const item of $input.all()) {
  try {
    const aiResponse = JSON.parse(item.json.choices[0].message.content);
    const vendorData = item.json.vendor_data || {};

    items.push({
      json: {
        vendor_name: aiResponse.vendor_name,
        vendor_email: vendorData.vendor_email,
        received_date: vendorData.received_date,
        message_id: vendorData.message_id,
        price_score: aiResponse.scores.price,
        capability_score: aiResponse.scores.capabilities,
        compliance_score: aiResponse.scores.compliance,
        sla_score: aiResponse.scores.sla,
        reference_score: aiResponse.scores.references,
        total_score: aiResponse.total_score,
        missing_fields: aiResponse.missing_fields,
        risk_flags: aiResponse.risk_flags,
        summary: aiResponse.summary,
        justifications: aiResponse.raw_scores_justification,
        timestamp: new Date().toISOString()
      }
    });
  } catch (error) {
    // Error handling - flag for manual review
    items.push({
      json: {
        vendor_name: 'PARSING_ERROR',
        error: error.message,
        raw_response: item.json,
        needs_manual_review: true,
        timestamp: new Date().toISOString()
      }
    });
  }
}

return items;

const allItems = $input.all();

const cleanedVendors = [];

for (const item of allItems) {
  try {
    let aiData = null;

    if (!item.json.needs_manual_review && item.json.total_score !== undefined) {
      aiData = item.json;
    } else if (item.json.raw_response?.output) {
      let raw = item.json.raw_response.output;
      raw = raw.replace(/```json/g, '').replace(/```/g, '').trim();
      aiData = JSON.parse(raw);
    }

    if (!aiData) continue;

    cleanedVendors.push({
      vendor_name: aiData.vendor_name || 'Unknown',
      vendor_email: item.json.vendor_email || null,
      received_date: item.json.received_date || null,
      message_id: item.json.message_id || null,

      price_score: aiData.scores?.price ?? null,
      capability_score: aiData.scores?.capabilities ?? null,
      compliance_score: aiData.scores?.compliance ?? null,
      sla_score: aiData.scores?.sla ?? null,
      reference_score: aiData.scores?.references ?? null,

      total_score: Number(aiData.total_score) || 0,
      missing_fields: aiData.missing_fields || [],
      risk_flags: aiData.risk_flags || [],
      summary: aiData.summary || '',
      justifications: aiData.raw_scores_justification || {},
      timestamp: new Date().toISOString()
    });

  } catch (err) {
    continue;
  }
}

// Sort
cleanedVendors.sort((a, b) => b.total_score - a.total_score);

// Add rank
cleanedVendors.forEach((v, index) => {
  v.rank = index + 1;
  v.rank_label =
    index === 0 ? '🥇 Top Choice' :
    index === 1 ? '🥈 Runner-up' :
    index === 2 ? '🥉 Third Place' :
    `#${index + 1}`;
});

// Summary
const totalVendors = cleanedVendors.length;

const averageScore = totalVendors > 0
  ? (
      cleanedVendors.reduce((sum, v) => sum + v.total_score, 0) /
      totalVendors
    ).toFixed(2)
  : 0;

// ✅ SINGLE OUTPUT OBJECT
return [
  {
    json: {
      vendors: cleanedVendors,
      summary: {
        total_vendors: totalVendors,
        average_score: averageScore,
        top_vendor: cleanedVendors[0]?.vendor_name || null,
        top_score: cleanedVendors[0]?.total_score || null,
        vendors_with_risks: cleanedVendors.filter(v => (v.risk_flags || []).length > 0).length,
        vendors_with_missing_data: cleanedVendors.filter(v => (v.missing_fields || []).length > 0).length,
        evaluation_date: new Date().toISOString()
      }
    }
  }
];

const output = [];

const inputItems = $input.all();

for (const item of inputItems) {

  const vendors = item.json.vendors || [];

  for (const vendor of vendors) {

    const missingFields = vendor.missing_fields || [];
    const riskFlags = vendor.risk_flags || [];

    let issues = [];

    // ✅ Priority: missing_fields
    if (missingFields.length > 0) {
      issues = missingFields;
    } 
    // ✅ Fallback: risk_flags
    else if (riskFlags.length > 0) {
      issues = riskFlags.map(r => `Clarification needed: ${r}`);
    } 
    // ✅ Fallback: generic
    else {
      issues = ["General clarification required on submitted proposal"];
    }

    const hasEmail = !!vendor.vendor_email;

    const emailBody = `Dear ${vendor.vendor_name} Team,

Thank you for submitting your RFP response.

We need clarification on the following:

${issues.map((field, i) => `${i + 1}. ${field}`).join('\n')}

Please respond within 3 business days.

Best regards,  
Procurement Team`;

    output.push({
      json: {
        to: vendor.vendor_email || "MISSING_EMAIL",
        subject: `RFP Follow-up - ${vendor.vendor_name}`,
        body: emailBody,
        vendor_name: vendor.vendor_name,
        issues_requested: issues,

        // 🔥 control flags
        can_send_email: hasEmail,
        needs_manual_review: !hasEmail,

        // optional context
        rank: vendor.rank,
        total_score: vendor.total_score
      }
    });
  }
}

return output;

const allVendors = $input.all();

// Get top 3 vendors
const topVendors = allVendors
  .filter(v => v.json.rank && v.json.rank <= 3)
  .sort((a, b) => a.json.rank - b.json.rank);

// Get summary
const summary = allVendors.find(v => v.json.total_vendors !== undefined);

const message = {
  blocks: [
    {
      type: "header",
      text: {
        type: "plain_text",
        text: "🎯 RFP Evaluation Complete - Vendor Shortlist"
      }
    },
    {
      type: "section",
      text: {
        type: "mrkdwn",
        text: `*Total Vendors Evaluated:* ${summary?.json.total_vendors || topVendors.length}\n*Average Score:* ${summary?.json.average_score || 'N/A'}\n*Evaluation Date:* ${new Date().toLocaleDateString()}`
      }
    },
    {
      type: "divider"
    }
  ]
};

// Add each top vendor
topVendors.forEach(vendor => {

  // ✅ Normalize risk_flags safely
  let riskFlags = vendor.json.risk_flags;

  if (!riskFlags) {
    riskFlags = [];
  } else if (typeof riskFlags === 'string') {
    riskFlags = [riskFlags];
  } else if (!Array.isArray(riskFlags)) {
    riskFlags = [];
  }

  const riskText = riskFlags.length > 0
    ? `\n\n⚠️ *Risks:* ${riskFlags.join(', ')}`
    : '';

  message.blocks.push(
    {
      type: "section",
      text: {
        type: "mrkdwn",
        text: `*${vendor.json.rank_label} ${vendor.json.vendor_name}*\n*Total Score:* ${vendor.json.total_score}/10\n\n*Breakdown:*\n• Price: ${vendor.json.price_score}/10\n• Capabilities: ${vendor.json.capability_score}/10\n• Compliance: ${vendor.json.compliance_score}/10\n• SLA: ${vendor.json.sla_score}/10\n• References: ${vendor.json.reference_score}/10\n\n*Summary:* ${vendor.json.summary}${riskText}`
      }
    },
    {
      type: "divider"
    }
  );
});

// Footer
message.blocks.push({
  type: "context",
  elements: [
    {
      type: "mrkdwn",
      text: "📊 Full details available in Google Sheets | ⚡ Powered by n8n + OpenRouter AI"
    }
  ]
});

return [{
  json: {
    channel: '#rfp-evaluations',
    text: 'RFP Evaluation Complete',
    blocks: JSON.stringify(message.blocks)
  }
}];
